// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Confirm received messages
	// (POST /confirmations)
	ConfirmMessages(ctx context.Context, request ConfirmMessagesRequestObject) (ConfirmMessagesResponseObject, error)
	// Delete endpoint
	// (DELETE /endpoints/{externalId})
	DeleteEndpoint(ctx context.Context, request DeleteEndpointRequestObject) (DeleteEndpointResponseObject, error)
	// Create or update endpoint
	// (PUT /endpoints/{externalId})
	PutEndpoint(ctx context.Context, request PutEndpointRequestObject) (PutEndpointResponseObject, error)
	// Receive events from agrirouter outbox
	// (GET /events)
	ReceiveEvents(ctx context.Context, request ReceiveEventsRequestObject) (ReceiveEventsResponseObject, error)
	// Send one or several messages to agrirouter inbox
	// (POST /messages)
	SendMessages(ctx context.Context, request SendMessagesRequestObject) (SendMessagesResponseObject, error)
	// List all authorized tenants and their related endpoints
	// (GET /tenants)
	ListAuthorizedTenants(ctx context.Context, request ListAuthorizedTenantsRequestObject) (ListAuthorizedTenantsResponseObject, error)
	// List tenant endpoints with route information
	// (GET /tenants/{tenantId}/endpoints)
	ListTenantEndpoints(ctx context.Context, request ListTenantEndpointsRequestObject) (ListTenantEndpointsResponseObject, error)
}

type StrictHandlerFunc = strictecho.StrictEchoHandlerFunc
type StrictMiddlewareFunc = strictecho.StrictEchoMiddlewareFunc

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
}

// ConfirmMessages operation middleware
func (sh *strictHandler) ConfirmMessages(ctx echo.Context, params ConfirmMessagesParams) error {
	var request ConfirmMessagesRequestObject

	request.Params = params

	var body ConfirmMessagesJSONRequestBody
	if err := ctx.Bind(&body); err != nil {
		return err
	}
	request.Body = &body

	handler := func(ctx echo.Context, request interface{}) (interface{}, error) {
		return sh.ssi.ConfirmMessages(ctx.Request().Context(), request.(ConfirmMessagesRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "ConfirmMessages")
	}

	response, err := handler(ctx, request)

	if err != nil {
		return err
	} else if validResponse, ok := response.(ConfirmMessagesResponseObject); ok {
		return validResponse.VisitConfirmMessagesResponse(ctx.Response())
	} else if response != nil {
		return fmt.Errorf("unexpected response type: %T", response)
	}
	return nil
}

